public int maxTwinSum(ListNode head) {
    int sum = 0, max_sum = 0, i = 0;
    ListNode slow = head, fast = head;

    while (fast != null && fast.next != null) {
        fast = fast.next.next;
        i++;
    }

    for (int j = 0; j < i; j++) {
        sum = slow.val + fast.val;
        max_sum = Math.max(max_sum, sum);
        slow = slow.next;
        fast = fast.prev;
    }

    return max_sum;
}
```

